import React, { useEffect, useState } from 'react';
import fileService from '../services/fileService';
function DownloadManager(){
  const [files,setFiles]=useState([]);
  const [passkeyById, setPasskeyById] = useState({});

  useEffect(()=>{ (async()=>{ try{ const res = await fileService.getSharedFiles(); setFiles(res); }catch(e){ console.error(e); } })(); },[]);
  const download=async(id)=>{
    try{
      let passkey = passkeyById[id] || '';
      if(!passkey){
        const entered = window.prompt('Enter passkey to decrypt and download:');
        if(!entered) return; // user cancelled or empty
        passkey = entered;
        setPasskeyById(prev => ({ ...prev, [id]: entered }));
      }
      const coords = await new Promise(resolve => {
        if (!navigator.geolocation) return resolve(null);
        navigator.geolocation.getCurrentPosition(
          p => resolve({ lat: p.coords.latitude, lng: p.coords.longitude }),
          () => resolve(null),
          { enableHighAccuracy: true, timeout: 5000 }
        );
      });
      await fileService.downloadWithPasskey(id, passkey, coords);
    }catch(e){
      try{
        // Axios may give a Blob for error responses with responseType:'blob'
        if(e?.response?.data instanceof Blob){
          const text = await e.response.data.text();
          try{
            const json = JSON.parse(text);
            alert(json.error || 'Failed');
          }catch{
            alert(text || 'Failed');
          }
        } else {
          alert(e?.response?.data?.error || e?.message || 'Failed');
        }
      }catch{
        alert('Failed');
      }
    }
  };
  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-100 flex flex-col items-center p-8">
      <div className="w-full max-w-4xl bg-white rounded-2xl shadow-lg p-8">
        <h2 className="text-3xl font-bold mb-6 text-blue-700">Files Shared With Me</h2>
        <div className="overflow-x-auto">
          <table className="min-w-full bg-white rounded-lg shadow border">
            <thead className="bg-blue-100">
              <tr>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">File ID</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">Name</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">Owner</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">Role</th>
                <th className="py-3 px-4 text-left font-semibold text-gray-700">Action</th>
              </tr>
            </thead>
            <tbody>
              {files.map(f => (
                <tr key={f.file_id} className="border-t hover:bg-blue-50 transition">
                  <td className="py-2 px-4">{f.file_id}</td>
                  <td className="py-2 px-4">{f.originalname}</td>
                  <td className="py-2 px-4">{f.owner_email}</td>
                  <td className="py-2 px-4">{f.role}</td>
                  <td className="py-2 px-4">
                    {(f.role === 'download' || f.role === 'share') ? (
                      <button onClick={() => download(f.file_id)} className="bg-green-500 text-white px-3 py-1 rounded-lg shadow hover:bg-green-600 transition">Download</button>
                    ) : (
                      <span className="text-gray-400">Not allowed</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
export default DownloadManager;
